%[text] # Polynomials, Curve-fitting and Interpolation
%[text] # 다항식, 커브 피팅, 인터폴레이션
myName = "양연우"; %[control:editfield:7d85]{"position":[10,15]}
disp("나의 이름은 " + myName + " 입니다."); %[output:9c1354e9]
%%
%[text] ## 다항식 / 多項式 / Polynomial
%[text] 다항식(多項式)은 한자로 \*\*많을 다(多), 항목 항(項), 법식 식(式)\*\*을 쓰며, '항이 여러 개(많다) 있는 식'을 뜻합니다. 1개 이상의 단항식 합으로 이루어진 식을 의미합니다. 
%[text] *참고: 하나뿐인 항으로 이루어진 식은 '단항식(單項式)'이라 합니다.* 
%[text] [https://kr.mathworks.com/help/releases/R2025b/matlab/polynomials.html](https://kr.mathworks.com/help/releases/R2025b/matlab/polynomials.html) 
%[text] ### 다항식의 예
%[text] $3x^2 +2x - 1$ : 2차 다항식
p = [3 2 -1]  % 다항식의 MATLAB 표현: 최고차 항부터 계수만 벡터로 나타냄  %[output:49c8653d]
%%
%[text] #### 연습문제 1: 다음 다항식을 MATLAB으로 나타내시오.
%[text]  1\. $x^4 - x^2 + 2$
p1 = [1 0 -1 0 2] %[output:2af81280]
%[text]  2\.  $1 -5x^5 + 3x^3 -x$
p2 = [-5 0 3 0 -1 1] %[output:27a0069f]
%%
%[text] #### 연습문제 2: 다음 MATLAB 표현에 해당하는 다항식을 수식으로 나타내시오.
p3 = [1 0 1 0 -1] %[output:78719125]
%[text]  1\. 다항식 수식: $x^4 + x^2 -1$
p4 = -2:2:2 %[output:921ac12b]
%[text]  2\. 다항식 수식: $-2x^2 + 2$
%%
%[text] ### 다항식이 아닌 것
%[text] 다항식(polynomial)은 변수의 덧셈, 뺄셈, 곱셈, 그리고 음이 아닌 정수 지수(차수)로 이루어진 식입니다. 따라서 **분모에 문자가 있는 식, 루트 안에 문자가 있는 식, 혹은 절대값 기호가 있는 식**은 다항식이 아닙니다. 
%[text] **다항식이 아닌 주요 예시**
%[text] - 분모에 변수가 있는 식: $\\frac{1}{x}$ ![](text:image:08c1), $\\frac{2x-1}{x^2}$ ![](text:image:1c77)등
%[text] - 루트 안에 문자가 있는 무리식: $\\sqrt{x}$ ![](text:image:139a), ![](text:image:34a5) $\\sqrt{x^2-1}$ 등
%[text] - 절대값 기호가 포함된 식: ![](text:image:1016)![](text:image:1907)![](text:image:3c3f)$|x|$, $|2x-1|$ ![](text:image:79bb)![](text:image:6cac)![](text:image:6d62)![](text:image:3f1f) 등
%[text] - 지수에 문자가 있는 식: $2^x$![](text:image:39c6), ![](text:image:9a0d) $e^{x^2-1}$등  \
%[text] 다항식은 $2x^2-x+5$와 같이 각 항이 수와 문자의 곱으로만 이루어져야 합니다. 
%[text] #### 연습문제 3: 다항식을 나타낸 그래프가 아닌 것을 모두 고르시오.
%[text] ![](text:image:0ef1)![](text:image:74cc)![](text:image:0fd2)
%[text] 1 1/x
%[text] 2 
%[text] 3 tan(x)
%%
%[text] ### 다항식의 계산
%[text] [`polyval`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/polyval.html)
%[text] 다항식 $f(x) = 3.75x^4 - 13.75x^2 + 5$ 에서 $x$가 -2 ~ 2의 범위를 가질 때 $f(x)$의 값은 다음과 같이 구합니다.
clear;
p = [3.75 0 -13.75 0 5]  % 다항식의 계수 %[output:8a8fc431]
x = linspace(-2, 2, 100); % x 값
y = polyval(p, x); % y 값
plot(x, y); grid on; %[output:7791f81c]
%%
%[text] #### 연습문제 4: $f(x) = 0.2x^3 -x^2 -x +1$의 그래프를 $-2 \< x \< 6$의 범위에 대하여 그리시오.
% your code
p = [0.2 -1 -1 1];
x = linspace(-2, 6, 100);
y = polyval(p, x);
plot(x, y); grid on; %[output:89616d2e]
%%
%[text] ### 다항식의 근
%[text] [`roots`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/roots.html)
%[text] $f(x)=0$이 되는 $x$를 다항식의 근(뿌리, roots)이라고 합니다. 
%[text] 다항식 $f(x) = x^5 -5x^3 +4x$ 의 근은 다음과 같이 구합니다. 
clear;
p = [1 0 -5 0 4 0] %[output:3ddb05d5]
r = roots(p) %[output:3eba66dc]
poly(r) %[output:335f3e17]
%%
%[text] $-2.5 \< x \< 2.5$의 범위에서 그래프를 그리고 근을 나타내면 다음과 같습니다.
x = linspace(-2.5, 2.5, 100);
y = polyval(p, x);
z = zeros(size(r));
plot(x, y, 'b-', r, z, 'bo'); %[output:0e4c6332]
grid on; ylim(5*[-1 1]); %[output:0e4c6332]
%%
%[text] #### 연습문제 5: 다항식 $f(x) = -2x -x^2 +x^3$의 그래프를 $-2 \< x \< 3$, $-5 \< y \< 5$의 범위에서 그리고 근을 나타내시오.
% your code
p = [1 -2 -2 0];
x = linspace(-2, 3, 100);
y = polyval(p, x);

r = roots(p);
z = zeros(size(r));

plot(x, y, 'b-', r, z, 'bo', 'MarkerFaceColor','r'); %[output:2ab66d97]
grid on; ylim([-5 5]); %[output:2ab66d97]
ax = gca;
ax.XTick = -2:3; %[output:2ab66d97]
ax.YTick = -5:5; %[output:2ab66d97]
%daspect([1 1 1])
%%
%[text] ### 다항식의 극대, 극소 (local maxima, local minima)
%[text] 다항식의 그래프에서 기울기가 0일 때 극대 또는 극소값을 갖는다.
%[text] 기울기가 0일 때는 다항식의 미분값은 0이 됩니다. 
%[text] 다항식 `p를 미분한 다항식은 polyder(p)로 구할 수 있습니다.`
%[text] [`polyder`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/polyder.html)
%[text] 다항식 $f(x) = -2x -x^2 +x^3$을 미분한 다항식 $q(x)= f^{'}(x)$는 다음과 같이 구할 수 있습니다.
clear;
p = [1 -1 -2 0];
q = polyder(p) %[output:26169870]
%[text] 따라서 $q(x)=3x^2 -2x -2$가 되는 것을 알 수 있습니다. 
%%
%[text] 미분값이 0일때 $f(x)$는 극대 또는 극소값을 갖습니다. 미분값 $q(x)=0$을 만족하는 $x$값은 다음과 같이 구할 수 있습니다. 
qz = roots(q) %[output:334ab447]
%[text] 이 때 $f(x)$ 값은 극대 또는 극소값에 해당하며 다음과 같이 구할 수 있습니다. 
pm = polyval(p, qz) %[output:59a8ba17]
%%
%[text] 다항식 $f(x) = -2x -x^2 +x^3$의 그래프를 $-2 \< x \< 3$, $-5 \< y \< 5$의 범위에서 극대, 극소값과 함께 그래프로 나타내면 다음과 같습니다. 
x = linspace(-2, 3, 100);
y = polyval(p, x);
plot(x, y, 'r-', qz, pm, 'ro', "MarkerFaceColor","r"); %[output:0a825d61]
grid on; ylim(5*[-1 1]); %[output:0a825d61]
%[text] 
%%
%[text] #### 연습문제 6: 다항식 $f(x) = x^5 -5x^3 +4x$ 의 그래프를  $-2.5 \< x \< 2.5$, $-5 \< y \< 5$의 범위에서 그리고, 근과 극대 극소를 함께 나타내시오.
%[text] ![](text:image:8222)
% your code 
clf; %[output:8fde3d34]
p = [1 0 -5 0 4 0];
x = linspace(-2.5, 2.5, 100);
y = polyval(p, x);

q = polyder(p);
qz = roots(q);
pm = polyval(p, qz);

r = roots(p);
z = zeros(size(r));

plot(x, y, 'r-'); hold on; %[output:8fde3d34]
plot(r, z, 'ro'); %[output:8fde3d34]
h = plot(qz, pm, 'ro', 'MarkerFaceColor', 'r'); %[output:8fde3d34]
grid on; ylim([-5 5]); %[output:8fde3d34]
title("양연우 길선영"); %[output:8fde3d34]
text(0, 3.5, "$f(x) = x^5 -5x^3 =4x$", 'Interpreter', 'latex'); %[output:8fde3d34]
xlabel("$x$", 'Interpreter', 'latex'); %[output:8fde3d34]
ylabel("$f(x)$", 'Interpreter', 'latex'); %[output:8fde3d34]
ax=gca;
ax.YTick = [-5 0 5]; %[output:8fde3d34]
%%
%[text] ## 커브 피팅 / Curve Fitting
%[text] [`polyfit`](http://mathworks.com/help/releases/R2025b/matlab/ref/polyfit.html)
%[text] $n$개 점의 $(x,y)$ 좌표를 나타내는 $n \\times 2$ 행렬을 $C$라고 할 때, 이 점들을 가장 잘 표현하는 $m$차 다항식의 계수 $p$는 다음과 같이 구할 수 있습니다.
%[text] `p = polyfit(C(:,1), C(:,2), m)`
%[text] `즉, polyfit()의 첫 번째 인수는 점들의` $x$좌표, 두 번째 인수는 $y$좌표이며, 세 번째 인수는 구하려는 다항식의 차수(order)입니다.
%%
%[text] ### 두 점을 통과하는 직선 (1차 다항식)
%[text] 두 점 (-2, -1), (1, 2)를 통과하는 직선의 방정식은 다음과 같이 구할 수 있습니다.
C = [-2 -1; 1 2]; xc = C(:,1); yc = C(:,2);
p = polyfit(xc, yc, 1) %[output:2e2ecb52]
x = linspace(-3, 2, 100);
y = polyval(p, x);
plot(x, y, 'b-', xc, yc, 'ro', "MarkerFaceColor","auto"); %[output:7969288f]
grid on; axis equal; %[output:7969288f]
%%
%[text] #### 10개의 랜덤 점을 통과하는 직선들
%[text] [`randi`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/double.randi.html)
%[text] $-5 \\sim 5$사이의 랜덤 두 점들을 통과하는 직선을 10개 그려볼까요?
K = 10;
clf; %[output:6195a7a8]
Cx = randi(50*[-1 1], 2, K)/10;
Cy = randi(50*[-1 1], 2, K)/10;
v = 100;
x = linspace(-6, 6, v)';
Y = zeros(v, K);
for k=1:K
    p = polyfit( Cx(:,k), Cy(:,k), 1);
    Y(:,k) = polyval(p, x);
end
plot(x,Y,'-',Cx,Cy,'o', "MarkerFaceColor","auto", "LineWidth",2); %[output:6195a7a8]
axis(6*[-1 1 -1 1]); axis square; daspect([1 1 1]); grid on; %[output:6195a7a8]
text(-6, -2, "사랑해요, 엄마 ❤️", 'Color', 'r') %[output:6195a7a8]
%ax = gca; ax.XTick = []; ax.YTick = [];
%%
%[text] ### 세 점을 통과하는 2차 다항식
%[text] 세 점 (-2, -1), (1, 2), (2,3)을 통과하는 2차 다항식은 다음과 같이 구할 수 있습니다.
C = [-2 -1; 1 2; 2 1]; xc = C(:,1); yc = C(:,2);
m = 2; % 다항식의 차수
p = polyfit(xc, yc, m) %[output:3f5bcdfd]
x = linspace(-3, 4, 100);
y = polyval(p, x);
plot(x, y, 'b-', xc, yc, 'ro', "MarkerFaceColor","auto"); %[output:5ec53c3a]
grid on; axis equal; %[output:5ec53c3a]
%%
%[text] #### 10개의 랜덤 세 점을 통과하는 곡선들
%[text] [`randi`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/double.randi.html)
%[text] $-5 \\sim 5$사이의 랜덤 세 점들을 통과하는 직선을 10개 그려볼까요?
n = 3;
K = 10;
Cx = randi(50*[-1 1], n, K)/10;
Cy = randi(50*[-1 1], n, K)/10;
v = 100;
x = linspace(-6, 6, v)';
Y = zeros(v, K);
for k=1:K
    p = polyfit( Cx(:,k), Cy(:,k), n-1);
    Y(:,k) = polyval(p, x);
end
plot(x,Y,'-',Cx,Cy,'o', "MarkerFaceColor","auto", "LineWidth",1); %[output:008aff92]
axis(6*[-1 1 -1 1]); axis square; daspect([1 1 1]); grid on; %[output:008aff92]
% ax = gca; ax.XTick = []; ax.YTick = [];
%%
%[text] ### 실험 데이터를 가장 잘 표현하는 직선
%[text] 다음은 실험을 통해 측정한 데이터를 나타낸 것입니다. 
clear; clf; %[output:04662fe7]
load expdata;
scatter(xc, yc, 10, abs(xc+yc)); %[output:04662fe7]
grid on; axis square; daspect([1 1 1]); %[output:04662fe7]
xlabel("$x$", "Interpreter","latex"); %[output:04662fe7]
ylabel("$y$", "Interpreter","latex"); %[output:04662fe7]
%%
%[text] 과연 이 실험 데이터를 가장 잘 나타내는 직선의 방정식은 어떻게 될까요?
p = polyfit(xc, yc, 1) %[output:0e1990db]
%[text] 이 직선의 방정식을 실험 데이터와 함께 나타냅니다.
x = linspace(-100, 100, 2);
y = polyval(p, x);
hold on; plot(x, y, 'b-', "LineWidth", 2); %[output:385e2ee4]
hold off; %[output:385e2ee4]
%%
%[text] 또 다른 실험 데이터 세트 `(xd, yd)`를 관찰해 보겠습니다.
clear; clf; %[output:5475e9aa]
load expdata;
scatter(xd, yd, 10, abs(xd+yd)); grid on; %[output:5475e9aa]
xlabel("$x$", "Interpreter","latex"); %[output:5475e9aa]
ylabel("$y$", "Interpreter","latex"); %[output:5475e9aa]
%[text] 
%%
%[text] #### 부록: 실험 데이터
%[text] - 선형 관계: $y = ax+b$ \
N = 50;
xc = randi([-100 100], N, 1);
yc = 1.1*xc + 1 + 100*rand(N,1);
scatter(xc, yc, 10, abs(xc+yc)); %[output:779408a8]
grid on; axis square; daspect([1 1 1]); %[output:779408a8]
save expdata xc yc;
%%
%[text] - 지수 관계: $y = e^{ax+b}$ \
clear;
N  = 100;
xd = 7*rand(N, 1) - 3;
yd = exp(0.5*xd + rand(N,1));
scatter(xd, yd, 10, abs(xd+yd)); %[output:258c6ef2]
grid on; %[output:258c6ef2]
save expdata xd yd -append
